mapper.select:
SELECT CONCAT(CONVERT(varchar(10), a.tran_date, 23), ' - ', a.seq) AS tranDateSeq ,s.storage_name AS srcStorageName ,s1.storage_name AS tarStorageName ,CASE WHEN COUNT(b.tran_item_id) = 1 THEN MIN(c.item_name) ELSE MIN(c.item_name) + ' 외 ' + CAST(COUNT(b.tran_item_id) - 1 AS VARCHAR) + '건' END AS itemName ,a.tran_id AS tranId ,SUM(ISNULL(b.qty, 0)) AS qty ,d.member_nm AS managerName ,a.etc ,e.customer_name AS customerName ,a.customer_cd AS customerCd FROM tb_inv_tran_mst a INNER JOIN tb_inv_tran_item b ON b.tran_id = a.tran_id INNER JOIN tb_item_mst c ON c.item_cd = b.item_cd INNER JOIN tb_users d ON d.user_id = a.manager_id LEFT OUTER JOIN tb_storage_mst s ON s.storage_cd = a.src_storage_cd LEFT OUTER JOIN tb_storage_mst s1 ON s1.storage_cd = a.tar_storage_cd LEFT OUTER JOIN tb_customer e ON e.customer_cd = a.customer_cd WHERE a.tran_date BETWEEN #{strDate} AND #{endDate}
AND a.tran_type_cd = #{tranTypeCd}
AND a.src_storage_cd = #{srcStorageCd}
AND a.tar_storage_cd = #{tarStorageCd}
AND b.item_cd LIKE '%' + #{itemCd} + '%'
AND c.item_name LIKE '%' + #{itemName} + '%'
AND e.customer_name LIKE '%' + #{customerName} + '%'
GROUP BY a.tran_date, a.seq, s.storage_name, s1.storage_name, a.tran_id, d.member_nm, a.etc, e.customer_name, a.customer_cd ORDER BY a.tran_date DESC, a.seq DESC

mapper.insert:
INSERT INTO dbo.tb_inv_tran_mst (
    tran_date, tran_type_cd, area_cd, tar_storage_cd, src_storage_cd, customer_cd, manager_id, remark,
    tran_status, end_yn,  pur_id, reg_id, upd_id, seq
)
VALUES (
    #{tranDate}, #{tranTypeCd}, #{areaCd}, #{tarStorageCd}, #{srcStorageCd}, #{customerCd},#{managerId}, #{remark},
    #{tranStatus}, #{endYn}, #{purId}, #{userId}, #{userId},
    (
    SELECT ISNULL(MAX(seq), 0) + 1
    FROM dbo.tb_inv_tran_mst WITH (UPDLOCK, HOLDLOCK)
    WHERE tran_type_cd = #{tranTypeCd}
    AND tran_date = #{tranDate}
    )
)

mapper.update:
UPDATE dbo.tb_inv_tran_mst
SET    tran_date        = #{tranDate}
      ,area_cd          = #{areaCd}
      ,tar_storage_cd  = #{tarStorageCd}
      ,src_storage_cd    = #{srcStorageCd}
      ,customer_cd      = #{customerCd}
      ,manager_id       = #{managerId}
      ,remark           = #{remark}
      ,upd_id           = #{userId}
      ,upd_dt           = GETDATE()
WHERE  pur_id           = #{purId}
and    tran_type_cd = 'A'

UPDATE  tb_inv_tran_item
SET      spec         = #{spec}
        ,qty          = #{qty}
        ,lot_no       = #{lotNo}
        ,etc          = #{etc}
        ,upd_id       = #{userId}
        ,upd_dt       = GETDATE()
WHERE pur_item_id  = #{purItemId}

